test_traj.command:
cat <<'EOF' > test_alive.ll
; Test for alive-tv verification
define i1 @test_and_simplify(i8 %a, i8 %b) {
  %cmp = icmp eq i8 %a, %b
  %x = icmp eq i8 %a, %b
  %and = and i1 %cmp, %x
  ret i1 %and
}

define i1 @test_and_simplify_ref(i8 %a, i8 %b) {
  %cmp = icmp eq i8 %a, %b
  ret i1 %cmp
}
EOF

cat <<'EOF' > test_alive2.ll
; Test for alive-tv verification - show the transformation
define i1 @src(i8 %a, i8 %b) {
  %cmp = icmp eq i8 %a, %b
  %x = icmp eq i8 %a, %b
  %and = and i1 %cmp, %x
  ret i1 %and
}

define i1 @tgt(i8 %a, i8 %b) {
  %cmp = icmp eq i8 %a, %b
  ret i1 %cmp
}
EOF
